 1→import { access, readdir } from "node:fs/promises";
 2→import { homedir } from "node:os";
 3→import { basename, dirname, join } from "node:path";
 4→import { decodeProjectPath } from "@rudel/agent-adapters";
 5→
 6→export const SESSIONS_BASE_DIR = join(homedir(), ".claude", "projects");
 7→
 8→export interface SessionInfo {
 9→	transcriptPath: string;
10→	projectPath: string;
11→	sessionDir: string;
12→	sessionId: string;
13→}
14→
15→export async function resolveSession(input: string): Promise<SessionInfo> {
16→	const isPath = input.includes("/") || input.endsWith(".jsonl");
17→
18→	if (isPath) {
19→		return resolveFromPath(input);
20→	}
21→	return resolveFromId(input);
22→}
23→
24→async function resolveFromPath(filePath: string): Promise<SessionInfo> {
25→	const filename = basename(filePath);
26→	validateNotSubagent(filename);
27→
28→	try {
29→		await access(filePath);
30→	} catch {
31→		throw new Error(`Session file not found: ${filePath}`);
32→	}
33→
34→	const sessionId = filename.replace(/\.jsonl$/, "");
35→	const sessionDir = dirname(filePath);
36→
37→	// Walk up from sessionDir to find the project directory name
38→	// Sessions live at: ~/.claude/projects/<encoded-project-dir>/<sessionId>.jsonl
39→	const parentDir = basename(sessionDir);
40→	const projectPath = await decodeProjectPath(parentDir);
41→
42→	return { transcriptPath: filePath, projectPath, sessionDir, sessionId };
43→}
44→
45→async function resolveFromId(sessionId: string): Promise<SessionInfo> {
46→	validateNotSubagent(`${sessionId}.jsonl`);
47→	const sessionFileName = `${sessionId}.jsonl`;
48→
49→	let projectDirs: string[];
50→	try {
51→		projectDirs = await readdir(SESSIONS_BASE_DIR);
52→	} catch {
53→		throw new Error(`Session not found: ${sessionId}`);
54→	}
55→
56→	for (const projectDir of projectDirs) {
57→		const sessionDir = join(SESSIONS_BASE_DIR, projectDir);
58→		try {
59→			const files = await readdir(sessionDir);
60→			if (files.includes(sessionFileName)) {
61→				const transcriptPath = join(sessionDir, sessionFileName);
62→				const projectPath = await decodeProjectPath(projectDir);
63→				return {
64→					transcriptPath,
65→					projectPath,
66→					sessionDir,
67→					sessionId,
68→				};
69→			}
70→		} catch {}
71→	}
72→
73→	throw new Error(`Session not found: ${sessionId}`);
74→}
75→
76→function validateNotSubagent(filename: string): void {
77→	if (filename.startsWith("agent-") && filename.endsWith(".jsonl")) {
78→		throw new Error(
79→			"This is a subagent file, not a main session. Please provide the main session ID or path.",
80→		);
81→	}
82→}
