31→export async function readJsonlFirstLine(
32→	filePath: string,
33→): Promise<unknown | null> {
34→	try {
35→		const content = await readFile(filePath, "utf-8");
36→		const firstLine = content.split("\n")[0];
37→		if (!firstLine) return null;
38→		return JSON.parse(firstLine);
39→	} catch {
40→		return null;
41→	}
42→}
43→
44→export async function walkJsonlFiles(dir: string): Promise<string[]> {
45→	const results: string[] = [];
46→
47→	let entries: string[];
48→	try {
49→		entries = await readdir(dir);
50→	} catch {
51→		return results;
52→	}
53→
54→	for (const entry of entries) {
55→		const fullPath = join(dir, entry);
56→		if (entry.endsWith(".jsonl")) {
57→			results.push(fullPath);
58→		} else if (!entry.includes(".")) {
59→			const nested = await walkJsonlFiles(fullPath);
60→			results.push(...nested);
61→		}
62→	}
63→
64→	return results;
65→}
