74→export function groupProjectsForCwd(
75→	projects: ScannedProject[],
76→	cwd: string,
77→): GroupedProjects {
78→	const current = projects.filter((p) => p.projectPath === cwd);
79→	const currentSet = new Set(current);
80→	const subfolders = projects.filter(
81→		(p) => !currentSet.has(p) && p.projectPath.startsWith(`${cwd}/`),
82→	);
83→	const subfoldersSet = new Set(subfolders);
84→	const others = projects.filter(
85→		(p) => !currentSet.has(p) && !subfoldersSet.has(p),
86→	);
87→
88→	subfolders.sort((a, b) => a.projectPath.localeCompare(b.projectPath));
89→	others.sort((a, b) => a.displayPath.localeCompare(b.displayPath));
90→
91→	return { current, subfolders, others };
