162→		} catch {
163→			return [];
164→		}
165→
166→		const projects: ScannedProject[] = [];
167→
168→		for (const dir of projectDirs) {
169→			const sessionDir = `${SESSIONS_BASE_DIR}/${dir}`;
170→			let files: string[];
171→			try {
172→				files = await readdir(sessionDir);
173→			} catch {
