325→	private async listSessionFiles(
326→		sessionDir: string,
327→		projectPath: string,
328→	): Promise<SessionFile[]> {
329→		try {
330→			const entries = await readdir(sessionDir);
331→			return entries
332→				.filter((f) => f.endsWith(".jsonl") && !f.startsWith("agent-"))
333→				.map((f) => ({
334→					sessionId: f.replace(/\.jsonl$/, ""),
335→					transcriptPath: join(sessionDir, f),
336→					projectPath,
337→				}));
338→		} catch {
339→			return [];
340→		}
341→	}
342→
343→	private async findByDecoding(projectPath: string): Promise<SessionFile[]> {
344→		let projectDirs: string[];
345→		try {
346→			projectDirs = await readdir(SESSIONS_BASE_DIR);
347→		} catch {
348→			return [];
349→		}
350→
351→		for (const dir of projectDirs) {
352→			try {
353→				const decoded = await decodeProjectPath(dir);
354→				if (decoded === projectPath) {
355→					const sessionDir = join(SESSIONS_BASE_DIR, dir);
356→					return this.listSessionFiles(sessionDir, projectPath);
357→				}
358→			} catch {
359→				// skip undecodable dirs
360→			}
361→		}
362→
363→		return [];
364→	}
365→}
