 28→		getGitBranch(cwd),
 29→		getGitSha(cwd),
 30→		getPackageInfo(cwd),
 31→	]);
 32→
 33→	const gitRemote = remoteUrl ? normalizeRemoteUrl(remoteUrl) : undefined;
 34→
 35→	return {
 36→		gitRemote,
 37→		packageName: packageInfo?.name,
 38→		packageType: packageInfo?.type,
 39→		branch: branch ?? undefined,
 40→		sha: sha ?? undefined,
 41→	};
 42→}
