 44→interface PackageInfo {
 45→	name: string;
 46→	type: string;
 47→}
 48→
 49→async function getPackageInfo(cwd: string): Promise<PackageInfo | null> {
 50→	try {
 51→		const gitRootResult =
 52→			await $`git -C ${cwd} rev-parse --show-toplevel`.quiet();
 53→		const root =
 54→			gitRootResult.exitCode === 0 ? gitRootResult.text().trim() : cwd;
 55→
 56→		return (
 57→			(await getNodePackage(root)) ??
 58→			(await getPythonPackage(root)) ??
 59→			(await getRustPackage(root)) ??
 60→			(await getGoModule(root))
 61→		);
 62→	} catch {
 63→		return null;
 64→	}
 65→}
 66→
 67→async function getNodePackage(root: string): Promise<PackageInfo | null> {
 68→	try {
 69→		const file = Bun.file(join(root, "package.json"));
 70→		if (!(await file.exists())) return null;
 71→		const pkg = await file.json();
 72→		return pkg.name ? { name: pkg.name, type: "package.json" } : null;
 73→	} catch {
 74→		return null;
 75→	}
 76→}
 77→
 78→async function getPythonPackage(root: string): Promise<PackageInfo | null> {
 79→	try {
 80→		const file = Bun.file(join(root, "pyproject.toml"));
 81→		if (!(await file.exists())) return null;
 82→		const content = await file.text();
 83→		const name = content.match(/^\s*name\s*=\s*"([^"]+)"/m)?.[1];
 84→		return name ? { name, type: "pyproject.toml" } : null;
 85→	} catch {
 86→		return null;
 87→	}
 88→}
 89→
 90→async function getRustPackage(root: string): Promise<PackageInfo | null> {
 91→	try {
 92→		const file = Bun.file(join(root, "Cargo.toml"));
 93→		if (!(await file.exists())) return null;
 94→		const content = await file.text();
 95→		const name = content.match(/^\s*name\s*=\s*"([^"]+)"/m)?.[1];
 96→		return name ? { name, type: "Cargo.toml" } : null;
 97→	} catch {
 98→		return null;
 99→	}
100→}
101→
102→async function getGoModule(root: string): Promise<PackageInfo | null> {
103→	try {
104→		const file = Bun.file(join(root, "go.mod"));
105→		if (!(await file.exists())) return null;
106→		const content = await file.text();
107→		const name = content.match(/^module\s+(\S+)/m)?.[1];
108→		return name ? { name, type: "go.mod" } : null;
109→	} catch {
110→		return null;
111→	}
112→}
113→
114→export async function getGitRemoteUrl(cwd: string): Promise<string | null> {
115→	try {
116→		const result = await $`git -C ${cwd} remote get-url origin`.quiet();
117→		if (result.exitCode !== 0) return null;
118→		return result.text().trim() || null;
119→	} catch {
120→		return null;
121→	}
122→}
123→
124→async function getGitBranch(cwd: string): Promise<string | null> {
125→	try {
126→		const result = await $`git -C ${cwd} rev-parse --abbrev-ref HEAD`.quiet();
127→		if (result.exitCode !== 0) return null;
128→		return result.text().trim();
129→	} catch {
130→		return null;
131→	}
132→}
133→
134→async function getGitSha(cwd: string): Promise<string | null> {
135→	try {
136→		const result = await $`git -C ${cwd} rev-parse HEAD`.quiet();
137→		if (result.exitCode !== 0) return null;
138→		return result.text().trim();
139→	} catch {
140→		return null;
141→	}
