 4→const CACHE_PATH = join(homedir(), ".rudel", "remote-cache.json");
 5→
 6→type RemoteCacheData = Record<string, string>;
 7→
 8→export async function getRemoteCache(): Promise<RemoteCacheData> {
 9→	try {
10→		const file = Bun.file(CACHE_PATH);
11→		if (!(await file.exists())) return {};
12→		return (await file.json()) as RemoteCacheData;
13→	} catch {
14→		return {};
15→	}
16→}
17→
18→export function getCachedRemote(
19→	cache: RemoteCacheData,
20→	encodedDir: string,
21→): string | null {
22→	return cache[encodedDir] ?? null;
23→}
24→
25→export function cacheRemote(
26→	cache: RemoteCacheData,
27→	encodedDir: string,
28→	normalizedRemote: string,
29→): void {
30→	cache[encodedDir] = normalizedRemote;
31→}
32→
33→export async function cacheRemotes(cache: RemoteCacheData): Promise<void> {
34→	try {
35→		const { mkdir } = await import("node:fs/promises");
36→		const { dirname } = await import("node:path");
37→		await mkdir(dirname(CACHE_PATH), { recursive: true });
38→		await Bun.write(CACHE_PATH, JSON.stringify(cache));
39→	} catch {
40→		// Fire-and-forget — cache is best-effort
41→	}
42→}
