  1→import { execSync } from "node:child_process";
  2→import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
  3→import { dirname, join, resolve } from "node:path";
  4→
  5→const HOOK_COMMAND = "rudel hooks claude session-end";
  6→
  7→interface HookEntry {
  8→	type: string;
  9→	command: string;
 10→	async?: boolean;
 11→}
 12→
 13→interface HookMatcher {
 14→	matcher: string;
 15→	hooks: HookEntry[];
 16→}
 17→
 18→interface ClaudeSettings {
 19→	hooks?: {
 20→		SessionEnd?: HookMatcher[];
 21→		[key: string]: unknown;
 22→	};
 23→	[key: string]: unknown;
 24→}
 25→
 26→function findClaudeDir(): string {
 27→	let dir = resolve(process.cwd());
 28→
 29→	while (dir !== dirname(dir)) {
 30→		const candidate = join(dir, ".claude");
 31→		if (existsSync(candidate)) {
 32→			return candidate;
 33→		}
 34→		dir = dirname(dir);
 35→	}
 36→
 37→	try {
 38→		const gitRoot = execSync("git rev-parse --show-toplevel", {
 39→			encoding: "utf-8",
 40→			stdio: ["pipe", "pipe", "pipe"],
 41→		}).trim();
 42→		return join(gitRoot, ".claude");
 43→	} catch {
 44→		return join(resolve(process.cwd()), ".claude");
 45→	}
 46→}
 47→
 48→export function getClaudeSettingsPath(): string {
 49→	return join(findClaudeDir(), "settings.json");
 50→}
 51→
 52→export function readClaudeSettings(): ClaudeSettings {
 53→	const path = getClaudeSettingsPath();
 54→	if (!existsSync(path)) return {};
 55→	const content = readFileSync(path, "utf-8");
 56→	return JSON.parse(content) as ClaudeSettings;
 57→}
 58→
 59→export function writeClaudeSettings(settings: ClaudeSettings): void {
 60→	const path = getClaudeSettingsPath();
 61→	mkdirSync(dirname(path), { recursive: true });
 62→	writeFileSync(path, `${JSON.stringify(settings, null, 2)}\n`);
 63→}
 64→
 65→export function isHookEnabled(): boolean {
 66→	const settings = readClaudeSettings();
 67→	const entries = settings.hooks?.SessionEnd;
 68→	if (!Array.isArray(entries)) return false;
 69→	return entries.some((entry) =>
 70→		entry.hooks?.some((h) => h.command === HOOK_COMMAND),
 71→	);
 72→}
 73→
 74→export function addHook(): void {
 75→	const settings = readClaudeSettings();
 76→	if (!settings.hooks) {
 77→		settings.hooks = {};
 78→	}
 79→	if (!Array.isArray(settings.hooks.SessionEnd)) {
 80→		settings.hooks.SessionEnd = [];
 81→	}
 82→
 83→	const alreadyExists = settings.hooks.SessionEnd.some((entry) =>
 84→		entry.hooks?.some((h) => h.command === HOOK_COMMAND),
 85→	);
 86→	if (alreadyExists) return;
 87→
 88→	settings.hooks.SessionEnd.push({
 89→		matcher: "",
 90→		hooks: [{ type: "command", command: HOOK_COMMAND, async: true }],
 91→	});
 92→
 93→	writeClaudeSettings(settings);
 94→}
 95→
 96→export function removeHook(): void {
 97→	const settings = readClaudeSettings();
 98→	const hooks = settings.hooks;
 99→	const entries = hooks?.SessionEnd;
100→	if (!hooks || !Array.isArray(entries)) return;
101→
102→	hooks.SessionEnd = entries.filter(
103→		(entry) => !entry.hooks?.some((h) => h.command === HOOK_COMMAND),
104→	);
105→
106→	if (hooks.SessionEnd.length === 0) {
107→		delete hooks.SessionEnd;
108→	}
109→	if (Object.keys(hooks).length === 0) {
110→		delete settings.hooks;
111→	}
112→
113→	writeClaudeSettings(settings);
114→}
