361→		items,
362→		label: "Retrying uploads...",
363→		concurrency: flags.concurrency,
364→		upload: async (item, onRetry) => {
365→			const adapter = item.failure.source
366→				? getAdapter(item.failure.source)
367→				: claudeCodeAdapter;
368→			const sessionFile: SessionFile = {
369→				sessionId: item.failure.sessionId,
370→				transcriptPath: item.failure.transcriptPath,
371→				projectPath: item.failure.projectPath,
