373→			const gitInfo = await getGitInfo(item.failure.projectPath);
374→			const organizationId =
375→				flags.org ??
376→				item.failure.organizationId ??
377→				(await getProjectOrgId(item.failure.projectPath));
378→
379→			const request = await adapter.buildUploadRequest(sessionFile, {
380→				tag: flags.tag,
381→				gitInfo,
382→				organizationId,
383→			});
384→
385→			return uploadSession(request, {
386→				endpoint,
387→				token: credentials.token,
