 37→async function runInteractiveUpload(flags: UploadFlags): Promise<void> {
 38→	const credentials = loadCredentials();
 39→	if (!credentials && !flags.dryRun) {
 40→		p.log.error("Not authenticated. Run `rudel login` first.");
 41→		process.exitCode = 1;
 42→		return;
 43→	}
 44→
 45→	p.intro("rudel upload");
 46→
 47→	const spin = p.spinner();
 48→	spin.start("Scanning projects...");
 49→
 50→	const adapters = getAvailableAdapters();
 51→	const allProjects: ScannedProject[] = [];
 52→	for (const adapter of adapters) {
 53→		const projects = await adapter.scanAllSessions();
 54→		allProjects.push(...projects);
 55→	}
 56→
 57→	spin.stop(`Found ${allProjects.length} project(s)`);
 58→
 59→	if (allProjects.length === 0) {
 60→		p.log.warn("No projects with sessions found.");
 61→		p.outro("Nothing to upload.");
 62→		return;
 63→	}
 64→
 65→	const cwd = process.cwd();
 66→	const grouped = groupProjectsForCwd(allProjects, cwd);
 67→
 68→	const options: Array<{
 69→		value: ScannedProject;
 70→		label: string;
 71→		hint: string;
 72→	}> = [];
 73→	const preSelected: ScannedProject[] = [];
 74→
 75→	for (const proj of grouped.current) {
 76→		options.push({
 77→			value: proj,
 78→			label: `[${getAdapterName(proj.source)}] ${proj.displayPath}`,
 79→			hint: sessionCountHint(proj.sessionCount),
 80→		});
 81→		preSelected.push(proj);
 82→	}
 83→
 84→	for (const sub of grouped.subfolders) {
 85→		const relative = sub.projectPath.slice(cwd.length + 1);
 86→		options.push({
 87→			value: sub,
 88→			label: `  [${getAdapterName(sub.source)}] ${relative}`,
 89→			hint: sessionCountHint(sub.sessionCount),
 90→		});
 91→		preSelected.push(sub);
 92→	}
 93→
 94→	for (const other of grouped.others) {
 95→		options.push({
 96→			value: other,
 97→			label: `[${getAdapterName(other.source)}] ${other.displayPath}`,
 98→			hint: sessionCountHint(other.sessionCount),
 99→		});
100→	}
101→
102→	const selected = await p.multiselect({
103→		message: "Select projects to upload",
104→		options,
105→		initialValues: preSelected,
106→		required: true,
107→	});
108→
109→	if (p.isCancel(selected)) {
110→		p.cancel("Upload cancelled.");
111→		return;
112→	}
113→
114→	const totalSessions = selected.reduce(
115→		(sum, proj) => sum + proj.sessionCount,
116→		0,
117→	);
118→	p.log.info(
119→		`Uploading ${totalSessions} session(s) from ${selected.length} project(s)`,
120→	);
121→
122→	const uploadConfig: UploadConfig = {
123→		endpoint: flags.endpoint,
124→		token: credentials?.token ?? "",
125→	};
126→
127→	// Flatten all sessions with their project context for concurrent upload
128→	const work: Array<{
129→		session: (typeof selected)[number]["sessions"][number];
130→		project: ScannedProject;
131→		adapter: ReturnType<typeof getAdapter>;
132→		gitInfo: Awaited<ReturnType<typeof getGitInfo>>;
133→		organizationId: string | undefined;
134→	}> = [];
135→
136→	for (const project of selected) {
137→		const adapter = getAdapter(project.source);
138→		const gitInfo = await getGitInfo(project.projectPath);
139→		const organizationId =
140→			flags.org ?? (await getProjectOrgId(project.projectPath));
141→		for (const session of project.sessions) {
142→			work.push({ session, project, adapter, gitInfo, organizationId });
143→		}
144→	}
145→
146→	type InteractiveItem = BatchUploadItem & {
147→		session: (typeof work)[number]["session"];
148→		adapter: (typeof work)[number]["adapter"];
149→		gitInfo: (typeof work)[number]["gitInfo"];
150→	};
151→
152→	const items: InteractiveItem[] = work.map((w) => ({
153→		sessionId: w.session.sessionId,
154→		label: `${w.project.displayPath}/${w.session.sessionId}`,
155→		transcriptPath: w.session.transcriptPath,
156→		projectPath: w.session.projectPath,
157→		source: w.project.source,
158→		organizationId: w.organizationId,
159→		session: w.session,
160→		adapter: w.adapter,
161→		gitInfo: w.gitInfo,
162→	}));
163→
164→	const summary = await runBatchUpload({
165→		items,
166→		label: "Uploading sessions...",
167→		concurrency: flags.concurrency,
168→		upload: async (item, onRetry) => {
169→			const request = await item.adapter.buildUploadRequest(item.session, {
170→				tag: flags.tag,
171→				gitInfo: item.gitInfo,
172→				organizationId: item.organizationId,
173→			});
174→
175→			if (!flags.tag && flags.classify) {
176→				const classified = await classifySession(request.content);
177→				if (classified) {
178→					(request as { tag?: string }).tag = classified;
179→				}
180→			}
181→
182→			if (flags.dryRun) {
183→				return { success: true };
184→			}
185→
186→			return uploadSession(request, { ...uploadConfig, onRetry });
187→		},
188→	});
189→
190→	renderBatchSummary(summary, { showRetryHint: summary.failed > 0 });
191→
192→	if (flags.dryRun) {
193→		p.outro("Dry run complete — no sessions were uploaded.");
194→	} else {
195→		p.outro("Done!");
196→	}
197→
198→	if (summary.failed > 0) {
199→		process.exitCode = 1;
200→	}
201→}
202→
203→function getAdapterName(source: Source): string {
204→	return getAdapter(source).name;
205→}
206→
207→function sessionCountHint(count: number): string {
208→	return `${count} session${count !== 1 ? "s" : ""}`;
209→}
