211→async function runSingleUpload(
212→	flags: UploadFlags,
213→	session: string,
214→): Promise<void> {
215→	const write = (msg: string) => {
216→		process.stdout.write(`${msg}\n`);
217→	};
218→	const writeError = (msg: string) => {
219→		process.stderr.write(`${msg}\n`);
220→	};
221→
222→	const credentials = loadCredentials();
223→	if (!credentials && !flags.dryRun) {
224→		writeError("Error: Not authenticated. Run `rudel login` first.");
225→		process.exitCode = 1;
226→		return;
227→	}
228→
229→	write(`Resolving session: ${session}`);
230→	let sessionInfo: Awaited<ReturnType<typeof resolveSession>>;
231→	try {
232→		sessionInfo = await resolveSession(session);
233→	} catch (error) {
234→		writeError(
235→			`Error: ${error instanceof Error ? error.message : String(error)}`,
236→		);
237→		process.exitCode = 1;
238→		return;
239→	}
240→	write(`Found session at: ${sessionInfo.transcriptPath}`);
241→
242→	const gitInfo = await getGitInfo(sessionInfo.projectPath);
243→	const displayName =
244→		gitInfo.gitRemote ||
245→		gitInfo.packageName ||
246→		sessionInfo.projectPath.split("/").pop();
247→	if (displayName) write(`Repository: ${displayName}`);
248→	if (gitInfo.branch) write(`Branch: ${gitInfo.branch}`);
249→
250→	const organizationId =
251→		flags.org ?? (await getProjectOrgId(sessionInfo.projectPath));
252→	if (organizationId) write(`Organization: ${organizationId}`);
253→
254→	write("Building upload request...");
255→	const sessionFile: SessionFile = {
256→		sessionId: sessionInfo.sessionId,
257→		transcriptPath: sessionInfo.transcriptPath,
258→		projectPath: sessionInfo.projectPath,
259→	};
260→
261→	const request = await claudeCodeAdapter.buildUploadRequest(sessionFile, {
262→		tag: flags.tag,
263→		gitInfo,
264→		organizationId,
265→	});
266→
267→	write(`Transcript: ${request.content.length} bytes`);
268→	if (request.subagents && request.subagents.length > 0) {
269→		write(`Subagents: ${request.subagents.length} file(s)`);
270→	}
271→
272→	if (!flags.tag && flags.classify) {
273→		write("Classifying session...");
274→		const classified = await classifySession(request.content);
275→		if (classified) {
276→			(request as { tag?: string }).tag = classified;
277→			write(`Classified as: ${classified}`);
278→		}
279→	}
280→
281→	if (flags.dryRun) {
282→		const preview = {
283→			...request,
284→			content: `[${request.content.length} bytes]`,
285→			subagents: request.subagents?.map((s) => ({
286→				...s,
287→				content: `[${s.content.length} bytes]`,
288→			})),
289→		};
290→		write("Dry run - would upload:");
291→		write(JSON.stringify(preview, null, 2));
292→		return;
293→	}
294→
295→	write("Uploading...");
296→	const result = await uploadSession(request, {
297→		endpoint: flags.endpoint,
298→		// biome-ignore lint/style/noNonNullAssertion: validated above with early return
299→		token: credentials!.token,
300→	});
301→
302→	if (result.success) {
303→		write("Upload successful!");
304→	} else {
305→		writeError(`Upload failed: ${result.error}`);
306→		process.exitCode = 1;
307→	}
308→}
