310→async function runRetryUpload(flags: UploadFlags): Promise<void> {
311→	const credentials = loadCredentials();
312→	if (!credentials) {
313→		p.log.error("Not authenticated. Run `rudel login` first.");
314→		process.exitCode = 1;
315→		return;
316→	}
317→
318→	p.intro("rudel upload --retry");
319→
320→	const failures = await loadFailedUploads();
321→	if (failures.length === 0) {
322→		p.outro("No failed uploads to retry.");
323→		return;
324→	}
325→
326→	p.log.info(`Found ${failures.length} failed upload(s):`);
327→	for (const f of failures.slice(0, 10)) {
328→		p.log.warn(`  ${f.sessionId}: ${f.error} (${f.failedAt})`);
329→	}
330→	if (failures.length > 10) {
331→		p.log.warn(`  ...and ${failures.length - 10} more`);
332→	}
333→
334→	const shouldRetry = await p.confirm({
335→		message: `Retry all ${failures.length} failed upload(s)?`,
336→		initialValue: true,
337→	});
338→
339→	if (p.isCancel(shouldRetry) || !shouldRetry) {
340→		p.cancel("Retry cancelled.");
341→		return;
342→	}
343→
344→	const endpoint = flags.endpoint;
345→
346→	type RetryItem = BatchUploadItem & {
347→		failure: (typeof failures)[number];
348→	};
349→
350→	const items: RetryItem[] = failures.map((f) => ({
351→		sessionId: f.sessionId,
352→		label: f.sessionId,
353→		transcriptPath: f.transcriptPath,
354→		projectPath: f.projectPath,
355→		source: f.source,
356→		organizationId: f.organizationId,
357→		failure: f,
358→	}));
359→
360→	const summary = await runBatchUpload({
361→		items,
362→		label: "Retrying uploads...",
363→		concurrency: flags.concurrency,
364→		upload: async (item, onRetry) => {
365→			const adapter = item.failure.source
366→				? getAdapter(item.failure.source)
367→				: claudeCodeAdapter;
368→			const sessionFile: SessionFile = {
369→				sessionId: item.failure.sessionId,
370→				transcriptPath: item.failure.transcriptPath,
371→				projectPath: item.failure.projectPath,
372→			};
373→			const gitInfo = await getGitInfo(item.failure.projectPath);
374→			const organizationId =
375→				flags.org ??
376→				item.failure.organizationId ??
377→				(await getProjectOrgId(item.failure.projectPath));
378→
379→			const request = await adapter.buildUploadRequest(sessionFile, {
380→				tag: flags.tag,
381→				gitInfo,
382→				organizationId,
383→			});
384→
385→			return uploadSession(request, {
386→				endpoint,
387→				token: credentials.token,
388→				onRetry,
389→			});
390→		},
391→	});
392→
393→	renderBatchSummary(summary);
394→
395→	p.outro("Done!");
396→
397→	if (summary.failed > 0) {
398→		process.exitCode = 1;
399→	}
400→}
401→
402→async function runUpload(
403→	flags: UploadFlags,
404→	...sessions: string[]
405→): Promise<void> {
406→	if (flags.retry) {
407→		return runRetryUpload(flags);
408→	}
409→	if (sessions.length === 0) {
410→		return runInteractiveUpload(flags);
411→	}
412→	return runSingleUpload(flags, sessions[0] as string);
413→}
