10→export async function readFileWithRetry(
11→	filePath: string,
12→	maxRetries = 5,
13→): Promise<string> {
14→	const delayMs = 500;
15→
16→	for (let attempt = 1; attempt <= maxRetries; attempt++) {
17→		try {
18→			return await readFile(filePath, "utf-8");
19→		} catch (error) {
20→			if (attempt < maxRetries) {
21→				await new Promise((resolve) => setTimeout(resolve, delayMs));
22→				continue;
23→			}
24→			throw error;
25→		}
26→	}
27→
28→	throw new Error(`Failed to read file: ${filePath}`);
29→}
