  1→import { homedir } from "node:os";
  2→import {
  3→	getAdapter,
  4→	getAvailableAdapters,
  5→	groupProjectsForCwd,
  6→	type ScannedProject,
  7→} from "@rudel/agent-adapters";
  8→import { buildCommand } from "@stricli/core";
  9→
 10→const CONDUCTOR_WORKSPACES_DIR = `${homedir()}/conductor/workspaces/`;
 11→
 12→function getConductorProject(projectPath: string): string | null {
 13→	if (!projectPath.startsWith(CONDUCTOR_WORKSPACES_DIR)) return null;
 14→	const rest = projectPath.slice(CONDUCTOR_WORKSPACES_DIR.length);
 15→	const slashIdx = rest.indexOf("/");
 16→	return slashIdx === -1 ? rest : rest.slice(0, slashIdx);
 17→}
 18→
 19→function getConductorWorkspaceName(projectPath: string): string {
 20→	const rest = projectPath.slice(CONDUCTOR_WORKSPACES_DIR.length);
 21→	const slashIdx = rest.indexOf("/");
 22→	return slashIdx === -1 ? rest : rest.slice(slashIdx + 1);
 23→}
 24→
 25→interface ConductorGroup {
 26→	project: string;
 27→	workspaces: Array<{ proj: ScannedProject; workspaceName: string }>;
 28→	totalSessions: number;
 29→}
 30→
 31→async function runListSessions(): Promise<void> {
 32→	const adapters = getAvailableAdapters();
 33→	const allProjects: ScannedProject[] = [];
 34→	for (const adapter of adapters) {
 35→		const projects = await adapter.scanAllSessions();
 36→		allProjects.push(...projects);
 37→	}
 38→
 39→	if (allProjects.length === 0) {
 40→		console.log("No projects with sessions found.");
 41→		return;
 42→	}
 43→
 44→	const cwd = process.cwd();
 45→	const grouped = groupProjectsForCwd(allProjects, cwd);
 46→
 47→	const lines: string[] = [];
 48→
 49→	// Collect all non-current projects, split into conductor groups and ungrouped
 50→	const allOthers = [...grouped.subfolders, ...grouped.others];
 51→	const conductorGroups = new Map<string, ConductorGroup>();
 52→	const ungrouped: ScannedProject[] = [];
 53→
 54→	for (const proj of allOthers) {
 55→		const conductorProject = getConductorProject(proj.projectPath);
 56→		if (conductorProject) {
 57→			let group = conductorGroups.get(conductorProject);
 58→			if (!group) {
 59→				group = { project: conductorProject, workspaces: [], totalSessions: 0 };
 60→				conductorGroups.set(conductorProject, group);
 61→			}
 62→			group.workspaces.push({
 63→				proj,
 64→				workspaceName: getConductorWorkspaceName(proj.projectPath),
 65→			});
 66→			group.totalSessions += proj.sessionCount;
 67→		} else {
 68→			ungrouped.push(proj);
 69→		}
 70→	}
 71→
 72→	// Check if current project is a conductor workspace
 73→	const currentProj = grouped.current[0] as ScannedProject | undefined;
 74→	const currentConductorProject = currentProj
 75→		? getConductorProject(currentProj.projectPath)
 76→		: null;
 77→
 78→	// Render current project (if not a conductor workspace)
 79→	for (const proj of grouped.current) {
 80→		if (getConductorProject(proj.projectPath)) continue;
 81→		const name = getAdapter(proj.source).name;
 82→		lines.push(
 83→			`[${name}] ${proj.displayPath} (${proj.sessionCount} sessions) [current]`,
 84→		);
 85→	}
 86→
 87→	// Render conductor groups, sorted by project name
 88→	const sortedGroups = [...conductorGroups.entries()].sort(([a], [b]) =>
 89→		a.localeCompare(b),
 90→	);
 91→	for (const [, group] of sortedGroups) {
 92→		// Include current project in its conductor group
 93→		let currentInGroup: ScannedProject | undefined;
 94→		if (currentProj && currentConductorProject === group.project) {
 95→			currentInGroup = currentProj;
 96→			group.totalSessions += currentProj.sessionCount;
 97→			group.workspaces.push({
 98→				proj: currentProj,
 99→				workspaceName: getConductorWorkspaceName(currentProj.projectPath),
100→			});
101→		}
102→
103→		group.workspaces.sort((a, b) =>
104→			a.workspaceName.localeCompare(b.workspaceName),
105→		);
106→
107→		const wsCount = group.workspaces.length;
108→		lines.push(
109→			`${group.project} (${wsCount} ${wsCount === 1 ? "workspace" : "workspaces"}, ${group.totalSessions} sessions)`,
110→		);
111→		for (const ws of group.workspaces) {
112→			const name = getAdapter(ws.proj.source).name;
113→			const current = ws.proj === currentInGroup ? " [current]" : "";
114→			lines.push(
115→				`  [${name}] ${ws.workspaceName} (${ws.proj.sessionCount} sessions)${current}`,
116→			);
117→		}
118→	}
119→
120→	// Render ungrouped others
121→	for (const other of ungrouped) {
122→		const name = getAdapter(other.source).name;
123→		lines.push(
124→			`[${name}] ${other.displayPath} (${other.sessionCount} sessions)`,
125→		);
126→	}
127→
128→	const totalSessions = allProjects.reduce((s, p) => s + p.sessionCount, 0);
129→	console.log(`${allProjects.length} projects, ${totalSessions} sessions\n`);
130→	for (const line of lines) {
131→		console.log(line);
132→	}
133→}
134→
135→export const listSessionsCommand = buildCommand({
136→	loader: async () => ({ default: runListSessions }),
137→	parameters: {},
138→	docs: {
139→		brief: "List session files that would appear in the upload picker",
140→	},
141→});
