import { homedir } from "node:os";
import {
	getAdapter,
	getAvailableAdapters,
	groupProjectsForCwd,
	type ScannedProject,
} from "@rudel/agent-adapters";
import { buildCommand } from "@stricli/core";

const CONDUCTOR_WORKSPACES_DIR = `${homedir()}/conductor/workspaces/`;

function getConductorProject(projectPath: string): string | null {
	if (!projectPath.startsWith(CONDUCTOR_WORKSPACES_DIR)) return null;
	const rest = projectPath.slice(CONDUCTOR_WORKSPACES_DIR.length);
	const slashIdx = rest.indexOf("/");
	return slashIdx === -1 ? rest : rest.slice(0, slashIdx);
}

function getConductorWorkspaceName(projectPath: string): string {
	const rest = projectPath.slice(CONDUCTOR_WORKSPACES_DIR.length);
	const slashIdx = rest.indexOf("/");
	return slashIdx === -1 ? rest : rest.slice(slashIdx + 1);
}

interface ConductorGroup {
	project: string;
	workspaces: Array<{ proj: ScannedProject; workspaceName: string }>;
	totalSessions: number;
}

async function runListSessions(): Promise<void> {
	const adapters = getAvailableAdapters();
	const allProjects: ScannedProject[] = [];
	for (const adapter of adapters) {
		const projects = await adapter.scanAllSessions();
		allProjects.push(...projects);
	}

	if (allProjects.length === 0) {
		console.log("No projects with sessions found.");
		return;
	}

	const cwd = process.cwd();
	const grouped = groupProjectsForCwd(allProjects, cwd);

	const lines: string[] = [];

	// Collect all non-current projects, split into conductor groups and ungrouped
	const allOthers = [...grouped.subfolders, ...grouped.others];
	const conductorGroups = new Map<string, ConductorGroup>();
	const ungrouped: ScannedProject[] = [];

	for (const proj of allOthers) {
		const conductorProject = getConductorProject(proj.projectPath);
		if (conductorProject) {
			let group = conductorGroups.get(conductorProject);
			if (!group) {
				group = { project: conductorProject, workspaces: [], totalSessions: 0 };
				conductorGroups.set(conductorProject, group);
			}
			group.workspaces.push({
				proj,
				workspaceName: getConductorWorkspaceName(proj.projectPath),
			});
			group.totalSessions += proj.sessionCount;
		} else {
			ungrouped.push(proj);
		}
	}

	// Check if current project is a conductor workspace
	const currentProj = grouped.current[0] as ScannedProject | undefined;
	const currentConductorProject = currentProj
		? getConductorProject(currentProj.projectPath)
		: null;

	// Render current project (if not a conductor workspace)
	for (const proj of grouped.current) {
		if (getConductorProject(proj.projectPath)) continue;
		const name = getAdapter(proj.source).name;
		lines.push(
			`[${name}] ${proj.displayPath} (${proj.sessionCount} sessions) [current]`,
		);
	}

	// Render conductor groups, sorted by project name
	const sortedGroups = [...conductorGroups.entries()].sort(([a], [b]) =>
		a.localeCompare(b),
	);
	for (const [, group] of sortedGroups) {
		// Include current project in its conductor group
		let currentInGroup: ScannedProject | undefined;
		if (currentProj && currentConductorProject === group.project) {
			currentInGroup = currentProj;
			group.totalSessions += currentProj.sessionCount;
			group.workspaces.push({
				proj: currentProj,
				workspaceName: getConductorWorkspaceName(currentProj.projectPath),
			});
		}

		group.workspaces.sort((a, b) =>
			a.workspaceName.localeCompare(b.workspaceName),
		);

		const wsCount = group.workspaces.length;
		lines.push(
			`${group.project} (${wsCount} ${wsCount === 1 ? "workspace" : "workspaces"}, ${group.totalSessions} sessions)`,
		);
		for (const ws of group.workspaces) {
			const name = getAdapter(ws.proj.source).name;
			const current = ws.proj === currentInGroup ? " [current]" : "";
			lines.push(
				`  [${name}] ${ws.workspaceName} (${ws.proj.sessionCount} sessions)${current}`,
			);
		}
	}

	// Render ungrouped others
	for (const other of ungrouped) {
		const name = getAdapter(other.source).name;
		lines.push(
			`[${name}] ${other.displayPath} (${other.sessionCount} sessions)`,
		);
	}

	const totalSessions = allProjects.reduce((s, p) => s + p.sessionCount, 0);
	console.log(`${allProjects.length} projects, ${totalSessions} sessions\n`);
	for (const line of lines) {
		console.log(line);
	}
}

export const listSessionsCommand = buildCommand({
	loader: async () => ({ default: runListSessions }),
	parameters: {},
	docs: {
		brief: "List session files that would appear in the upload picker",
	},
});

